// src/components/Navbar/Navbar.js
import React from 'react';

const Navbar = ({ activeMenu, setActiveMenu }) => {
    return (
        <nav style={{ 
            display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
            padding: '20px 80px', background: '#0c0a09', borderBottom: '1px solid #262626' 
        }}>
            <h1 style={{ color: '#ea580c', margin: 0 }}>PasukanYerusSolo</h1>
            <div style={{ display: 'flex', gap: '24px' }}>
                {['eksplorasi', 'favorit', 'status'].map(item => (
                    <button 
                        key={item} 
                        onClick={() => setActiveMenu(item)}
                        style={{ background: 'none', border: 'none', color: activeMenu === item ? '#f59e0b' : '#fff', fontWeight: '700' }}
                    >
                        {item.charAt(0).toUpperCase() + item.slice(1)}
                    </button>
                ))}
            </div>
            <button onClick={() => window.location.href='/login'} style={{ padding: '8px 20px', borderRadius: '20px', border: '1px solid #ea580c', background: 'transparent', color: '#ea580c' }}>Login</button>
        </nav>
    );
};
export default Navbar;
